def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                base = a ** 3
                temp = np.exp(-ratio * a) * base
                if a % 4 == 0:
                    temp *= 0.85
                elif a % 5 == 0:
                    temp *= 1.1
                else:
                    temp *= 1.03
                if base % 7 == 0:
                    temp += np.sin(ratio * a * np.pi)
                score += temp
            if (capacity + item) % 4 == 0 or (capacity - item) % 7 == 0:
                score *= 0.81
            if score > 12:
                score /= 3
        elif 0.05 <= ratio < 0.2:
            product = 1
            for n in range(1, int(capacity) + 3):
                term = ratio + (n ** 0.75) / (n + 1)
                product *= term
                if product > 2e6:
                    product = np.log1p(product) * 1.7
                    break
            mod_val = int(product) % 500
            score += np.sqrt(ratio * mod_val + 2)
            if (int(capacity) % 5 == 0) and (int(item * 3) % 4 == 0):
                score += 5.7
            else:
                score -= 1.1
            extra_sum = 0
            for x in range(1, 8):
                frac = ((ratio * x**2.3) % 1)
                extra_sum += frac * (x ** 2.3)
            score += extra_sum / 7
            if score > 50:
                score /= 2.5
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 9):
                increment = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 1.5) ** 1.2)
                if m % 2 == 0:
                    increment *= 1.15
                else:
                    increment *= 0.95
                score += increment
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.65
            else:
                score -= remainder * 1.1
            if score < -7:
                score = abs(score) * 0.4 + 3
            if int(capacity) % 9 == 0:
                score *= 1.35
            if score > 25:
                score /= 4
        elif 0.5 < ratio <= 0.8:
            penalty_base = 0
            for p in range(1, 12):
                val = ((ratio - 0.5) ** p) * (p ** 1.8)
                penalty_base += val
                if penalty_base > 70:
                    penalty_base = np.log1p(penalty_base) * 1.1
                    break
            score = penalty_base * 14
            if capacity < item * 1.1:
                score += 18
            if (int(capacity * 7) % 9 == 0) and (int(item * 11) % 13 == 0):
                score -= 8
            if score < 0:
                score *= -1.7
                score += 7
            if score > 130:
                score = 130
        elif 0.8 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.8
            for q in range(1, 14):
                val = ((diff) ** q) * (q ** 2.8) / (q + 0.7)
                penalty_ext += val
                if penalty_ext > 1300:
                    penalty_ext = np.sqrt(penalty_ext) * 1.2
                    break
            score = penalty_ext * 18
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 4) % 6 == 0) and (int(item * 10) % 7 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1400:
                score = 1400
        elif 1.2 < ratio <= 1.8:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.8)
                if term > 15000:
                    term = np.sqrt(term) * 1.1
                if r % 3 == 0:
                    term *= 0.92
                super_penalty += term
            score = super_penalty * 28
            if capacity < item * 2.3:
                score += 32
            if (int(capacity * 15) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 12
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 5
            if score > 2500:
                score = 2500
        else:
            ultra_penalty = 0
            diff = ratio - 1.8
            for s in range(1, 20):
                term = ((diff) ** s) * (s ** 4)
                if term > 25000:
                    term = np.cbrt(term)
                ultra_penalty += term
                if s % 5 == 0:
                    ultra_penalty += np.sin(diff * s * np.pi) * s
            score = ultra_penalty * 35
            if capacity < item * 3:
                score += 40
            if (int(capacity * 20) % 6 == 0) and (int(item * 23) % 7 == 0):
                score -= 14
            for v in range(1, 10):
                score += ((diff / (v + 0.3)) % 1) * (v * 3)
            if score < 0:
                score = abs(score) * 0.8 + 6
            if score > 3000:
                score = 3000
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
            if score < 5:
                score *= 1.1
        elif capacity < 4:
            score *= 2.5
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val * 1.1
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            if finite_priorities.size > 0:
                med = np.median(finite_priorities)
                std = np.std(finite_priorities)
                priorities[idx] = med if std < med * 0.7 else med * 0.9
            else:
                priorities[idx] = 0
    return priorities
